{
  "summary": "This paper introduces Continual Knowledge Learning (CKL), a formal continual learning framework for updating language models' internal knowledge from new corpora while preserving time-invariant knowledge. It proposes a new benchmark with datasets and a novel metric (FUAR), adapts existing continual learning methods as baselines, and provides extensive experiments on T5 and GPT-2 models highlighting challenges and promising directions for CKL.",
  "strengths": [
    {
      "point": "Novel problem formulation of continual knowledge learning",
      "evidence": "The paper formally defines CKL as a continual learning problem focused on updating internal world knowledge of LMs through continual pretraining on new corpora."
    },
    {
      "point": "Comprehensive benchmark and novel metric",
      "evidence": "The authors construct a new benchmark with datasets probing invariant, updated, and new knowledge (INVARIANT LAMA, UPDATED LAMA, NEW LAMA, NEW LAMA-EASY) and propose the FUAR metric to measure forgetting versus knowledge acquisition."
    },
    {
      "point": "Extensive empirical evaluation and insights",
      "evidence": "Experiments on T5 and GPT-2 models show parameter-expansion methods outperform others, rehearsal methods underperform, multiple update phases increase forgetting, and learning rate tuning can balance forgetting and learning."
    },
    {
      "point": "Commitment to public release",
      "evidence": "The authors commit to releasing all benchmark datasets, evaluation scripts, and baseline code to facilitate further research."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of empirical comparison to state-of-the-art knowledge editing methods",
      "evidence": "The paper positions CKL as distinct from knowledge editing but does not compare to recent methods like MEMIT or ROME that update specific facts without full retraining."
    },
    {
      "point": "Insufficient justification and analysis of corpus size discrepancy",
      "evidence": "The new corpus D1 is about 750 times smaller than the original pretraining corpus D0, but the paper lacks ablations varying this ratio or analyzing its effect on forgetting and learning."
    },
    {
      "point": "Missing ablations on modular method design choices",
      "evidence": "The Modular method freezes the original encoder and adds a randomly initialized encoder, but the paper does not ablate encoder size, initialization, or inference integration."
    },
    {
      "point": "Unclear implementation details and hyperparameter tuning for Mix-Review rehearsal",
      "evidence": "Poor performance of Mix-Review is reported without details on rehearsal buffer size, sampling strategy, or mixing ratio, making conclusions about rehearsal effectiveness premature."
    },
    {
      "point": "Limited analysis of FUAR metric sensitivity and interpretability",
      "evidence": "The paper does not analyze how FUAR responds to different weighting schemes or correlates with downstream task performance."
    },
    {
      "point": "Evaluation limited to zero-shot settings",
      "evidence": "All CKL benchmark evaluations are zero-shot; performance under fine-tuning or few-shot scenarios remains unexplored."
    },
    {
      "point": "Missing critical training hyperparameters and reproducibility details",
      "evidence": "Batch size, optimizer settings, learning rate schedules, and random seeds are omitted, hindering reproducibility and fair comparison."
    },
    {
      "point": "No timeline or platform specified for code release",
      "evidence": "Although code and datasets will be released, no timeline or hosting platform is provided."
    },
    {
      "point": "Ambiguity in defining time-invariant knowledge",
      "evidence": "The criteria distinguishing invariant from outdated knowledge in the benchmark datasets are not clearly specified."
    },
    {
      "point": "Insufficient explanation of NEW LAMA-EASY dataset construction",
      "evidence": "Minimal methodological details or examples are provided for the paraphrasing and decontextualization process."
    },
    {
      "point": "Memory inefficiency of parameter-expansion methods not addressed",
      "evidence": "The paper acknowledges parameter growth but does not propose or evaluate mitigation strategies like pruning or distillation."
    },
    {
      "point": "No analysis of potential negative transfer across CKL phases",
      "evidence": "Experiments show increased forgetting over multiple phases but do not investigate whether earlier knowledge updates interfere negatively with later ones."
    },
    {
      "point": "Limited model architectures and sizes evaluated",
      "evidence": "Experiments are restricted to T5-large and GPT-2 (~700M parameters), lacking evaluation on smaller, larger, or diverse architectures."
    },
    {
      "point": "Domain specificity of D1 corpus limits generalizability",
      "evidence": "D1 consists solely of news articles from a specific time window; other domains like scientific literature or social media are not explored."
    },
    {
      "point": "Downstream evaluation limited to KILT tasks",
      "evidence": "Other relevant tasks such as fact verification, dialogue generation, or knowledge-grounded summarization are not assessed."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare empirically to state-of-the-art knowledge editing methods like MEMIT or ROME?",
      "motivation": "Understanding practical advantages or limitations relative to targeted editing approaches is important for positioning CKL."
    },
    {
      "question": "How sensitive is the FUAR metric to different weighting schemes and how well does it correlate with downstream task performance?",
      "motivation": "Clarifying FUAR's interpretability and reliability would strengthen its utility as a benchmark metric."
    },
    {
      "question": "What are the effects of fine-tuning or few-shot adaptation on CKL methods' ability to retain and update knowledge?",
      "motivation": "Since zero-shot evaluation is limited, exploring more practical settings would inform real-world applicability."
    },
    {
      "question": "Can parameter-expansion methods be made more memory efficient through pruning or distillation without sacrificing performance?",
      "motivation": "Addressing memory growth is critical for scalability in continual knowledge learning."
    },
    {
      "question": "Does knowledge acquired in earlier CKL phases negatively transfer or interfere with later updates?",
      "motivation": "Understanding negative transfer dynamics is important for designing robust multi-phase continual learning."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
